INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, 0, 125801, 1, 1, "リリ", 1);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, 0, 126001, 1, 1, "クリア", 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "んーと。\nこれ、あげる。\nはい", 323, 0, 126101, 1, 1, "プレシア", 3);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, 0, 125801, 2, 1, "リリ", 4);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, 0, 126001, 2, 1, "クリア", 5);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 40011, 24001, "お兄。\nきてくれて、うれしい", 326, 0, 126101, 2, 1, "プレシア", 6);
